sql:
SELECT DISTINCT date_reported 
FROM case_details 
ORDER BY date_reported;

SELECT COUNT(*) AS active_cases_count
FROM case_details
WHERE region_id = 0 AND case_status = 'active';

SELECT DISTINCT facility_id
FROM treatment_facilities
ORDER BY facility_id;

SELECT region_name
FROM regions
ORDER BY region_name;

